502→    },
503→    "worktrees": {
504→      "type": "object",
505→      "additionalProperties": false,
506→      "required": [
507→        "enabled",
508→        "lease_ttl_seconds",
509→        "heartbeat_seconds",
510→        "coordination_store",
511→        "completion_write_branch",
512→        "dirty_worktree_policy"
