{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "repo-config.schema.json",
  "title": "dev-graph repository-local configuration",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "repository_id",
    "content_roots",
    "local_state",
    "github",
    "execution_tracker",
    "worktrees",
    "claude_hooks",
    "path_policy"
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "repository_id": {
      "type": "string",
      "description": "C24がcanonical GitHub remoteから再導出する github:<owner>/<repo>、またはremoteなしでgit common-dir realpathから導出するlocal fingerprint。設定値と再導出値の一致を必須とする。",
      "pattern": "^(github:[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+|local:sha256:[0-9a-f]{64})$"
    },
    "content_roots": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "issues",
        "tasks",
        "specifications",
        "architecture",
        "features",
        "documents",
        "system_spec"
      ],
      "properties": {
        "issues": {
          "$ref": "#/$defs/repoRelative"
        },
        "tasks": {
          "$ref": "#/$defs/repoRelative"
        },
        "specifications": {
          "$ref": "#/$defs/repoRelative"
        },
        "architecture": {
          "$ref": "#/$defs/repoRelative"
        },
        "features": {
          "$ref": "#/$defs/repoRelative"
        },
        "documents": {
          "$ref": "#/$defs/repoRelative"
        },
        "system_spec": {
          "$ref": "#/$defs/repoRelative"
        }
      }
    },
    "plan_roots": {
      "type": "object",
      "additionalProperties": false,
      "description": "system-dev-planner が plan の staging/published/state 置き場として読む任意セクション (promote-system-plan.py)。dev-graph 単体では未使用だが、同一 config を共有する以上 schema 側で正式に許可する (additionalProperties:false のため未定義だと実運用 config が schema 不適合になる)",
      "required": [
        "staging",
        "published",
        "state"
      ],
      "properties": {
        "staging": {
          "$ref": "#/$defs/repoRelative"
        },
        "published": {
          "$ref": "#/$defs/repoRelative"
        },
        "state": {
          "$ref": "#/$defs/repoRelative"
        }
      }
    },
    "local_state": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "graph",
        "cache",
        "locks"
      ],
      "properties": {
        "graph": {
          "$ref": "#/$defs/repoRelative"
        },
        "cache": {
          "$ref": "#/$defs/repoRelative"
        },
        "locks": {
          "$ref": "#/$defs/repoRelative"
        }
      }
    },
    "github": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "enabled",
        "issue_repository",
        "projects",
        "completion_policy"
      ],
      "properties": {
        "enabled": {
          "type": "boolean"
        },
        "issue_repository": {
          "type": "string",
          "pattern": "^[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+$"
        },
        "projects": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "alias",
              "owner_type",
              "owner_login",
              "project_number",
              "default",
              "auto_add",
              "field_mappings"
            ],
            "properties": {
              "alias": {
                "type": "string",
                "pattern": "^[a-z0-9][a-z0-9_-]*$"
              },
              "owner_type": {
                "type": "string",
                "enum": [
                  "organization",
                  "user"
                ]
              },
              "owner_login": {
                "type": "string",
                "minLength": 1
              },
              "project_number": {
                "type": "integer",
                "minimum": 1
              },
              "default": {
                "type": "boolean"
              },
              "auto_add": {
                "type": "object",
                "additionalProperties": false,
                "required": [
                  "artifact_kinds",
                  "confirmation_status",
                  "evaluation_status",
                  "implementation_readiness"
                ],
                "properties": {
                  "artifact_kinds": {
                    "type": "array",
                    "minItems": 1,
                    "uniqueItems": true,
                    "items": {
                      "type": "string",
                      "enum": [
                        "task",
                        "issue"
                      ]
                    }
                  },
                  "confirmation_status": {
                    "const": "confirmed"
                  },
                  "evaluation_status": {
                    "const": "pass"
                  },
                  "implementation_readiness": {
                    "const": "complete"
                  }
                }
              },
              "field_mappings": {
                "type": "array",
                "items": {
                  "type": "object",
                  "additionalProperties": false,
                  "required": [
                    "local_field",
                    "project_field_name",
                    "value_type",
                    "direction",
                    "option_map"
                  ],
                  "properties": {
                    "local_field": {
                      "type": "string",
                      "enum": [
                        "status",
                        "priority",
                        "start_date",
                        "target_date",
                        "iteration"
                      ]
                    },
                    "project_field_name": {
                      "type": "string",
                      "minLength": 1
                    },
                    "value_type": {
                      "type": "string",
                      "enum": [
                        "single_select",
                        "text",
                        "number",
                        "date",
                        "iteration"
                      ]
                    },
                    "direction": {
                      "type": "string",
                      "enum": [
                        "local_to_project",
                        "bidirectional"
                      ]
                    },
                    "option_map": {
                      "type": "object",
                      "additionalProperties": {
                        "type": "string"
                      }
                    }
                  },
                  "allOf": [
                    {
                      "if": {
                        "properties": {
                          "local_field": {
                            "const": "status"
                          }
                        }
                      },
                      "then": {
                        "properties": {
                          "direction": {
                            "const": "local_to_project"
                          }
                        }
                      }
                    }
                  ]
                }
              }
            }
          }
        },
        "completion_policy": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "trigger",
            "required_pull_requests",
            "target_branch",
            "closed_unmerged",
            "issue_reopened",
            "revert",
            "local_reconciliation",
            "scheduled_reconciliation"
          ],
          "properties": {
            "trigger": {
              "const": "linked_pr_merged"
            },
            "required_pull_requests": {
              "type": "string",
              "enum": [
                "all",
                "any"
              ]
            },
            "target_branch": {
              "const": "default"
            },
            "closed_unmerged": {
              "type": "string",
              "enum": [
                "keep_active",
                "mark_blocked"
              ]
            },
            "issue_reopened": {
              "const": "reopen_task"
            },
            "revert": {
              "const": "create_follow_up_unless_issue_reopened"
            },
            "local_reconciliation": {
              "type": "array",
              "minItems": 1,
              "uniqueItems": true,
              "items": {
                "type": "string",
                "enum": [
                  "manual_sync",
                  "claude_hook",
                  "scheduled_sync"
                ]
              }
            },
            "scheduled_reconciliation": {
              "type": "object",
              "additionalProperties": false,
              "required": [
                "enabled",
                "interval_minutes",
                "owner",
                "entry_point"
              ],
              "properties": {
                "enabled": {
                  "type": "boolean"
                },
                "interval_minutes": {
                  "type": "integer",
                  "minimum": 5,
                  "maximum": 10080
                },
                "owner": {
                  "type": "string",
                  "enum": [
                    "claude_session_start",
                    "host_scheduler"
                  ]
                },
                "entry_point": {
                  "const": "dev-graph sync --reconcile-lifecycle"
                }
              }
            }
          },
          "allOf": [
            {
              "if": {
                "properties": {
                  "local_reconciliation": {
                    "contains": {
                      "const": "scheduled_sync"
                    }
                  }
                }
              },
              "then": {
                "properties": {
                  "scheduled_reconciliation": {
                    "properties": {
                      "enabled": {
                        "const": true
                      }
                    }
                  }
                }
              }
            },
            {
              "if": {
                "properties": {
                  "scheduled_reconciliation": {
                    "properties": {
                      "enabled": {
                        "const": true
                      }
                    }
                  }
                }
              },
              "then": {
                "properties": {
                  "local_reconciliation": {
                    "contains": {
                      "const": "scheduled_sync"
                    }
                  }
                }
              }
            }
          ]
        }
      },
      "allOf": [
        {
          "if": {
            "properties": {
              "enabled": {
                "const": true
              }
            }
          },
          "then": {
            "properties": {
              "projects": {
                "minItems": 1,
                "contains": {
                  "type": "object",
                  "properties": {
                    "default": {
                      "const": true
                    }
                  },
                  "required": [
                    "default"
                  ]
                },
                "minContains": 1,
                "maxContains": 1
              }
            }
          }
        }
      ]
    },
    "execution_tracker": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "mode"
      ],
      "description": "repo単位の実行トラッカー選択。既定・repoプロファイル別の選択基準はreferences/execution-tracker-contract.md §1の決定表を正本とする。",
      "properties": {
        "mode": {
          "type": "string",
          "enum": [
            "beads",
            "github",
            "both"
          ]
        },
        "beads": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "issue_prefix",
            "server_mode",
            "github_mirror",
            "board"
          ],
          "properties": {
            "issue_prefix": {
              "type": "string",
              "pattern": "^[a-z][a-z0-9-]*$"
            },
            "server_mode": {
              "type": "boolean",
              "description": "bd を server モードで運用するか。strandkanban 0.5.x (旧称 beads-kanban) は bd export/update 等の CLI で読み書きし bd sql を使わないため、board=beads-kanban でも embedded (false) のままでよい (旧版の bd sql 読取時代にあった true 強制は撤廃。契約 §9.1 正本)。"
            },
            "github_mirror": {
              "type": "string",
              "enum": [
                "bd_github_push_only",
                "none"
              ]
            },
            "board": {
              "type": "string",
              "description": "beads 束縛タスクの live 看板 UI 選択 (references/execution-tracker-contract.md §9 正本)。beads-kanban=doublej/strandkanban (旧称 beads-kanban、enum 値は後方互換のため旧名を維持。embedded bd で動作・clone+install で起動・外部依存・LICENSE要確認)。static-render=C05 render-graph-html のゼロ依存スナップショットのみ。omb-board=oh-my-beads 同梱の軽量 board (embedded 可)。none=看板なし。",
              "enum": [
                "beads-kanban",
                "static-render",
                "omb-board",
                "none"
              ]
            }
          }
        }
      },
      "allOf": [
        {
          "if": {
            "properties": {
              "mode": {
                "enum": [
                  "beads",
                  "both"
                ]
              }
            }
          },
          "then": {
            "required": [
              "beads"
            ]
          }
        }
      ]
    },
    "worktrees": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "enabled",
        "lease_ttl_seconds",
        "heartbeat_seconds",
        "coordination_store",
        "completion_write_branch",
        "dirty_worktree_policy"
      ],
      "properties": {
        "enabled": {
          "type": "boolean"
        },
        "lease_ttl_seconds": {
          "type": "integer",
          "minimum": 300,
          "maximum": 86400
        },
        "heartbeat_seconds": {
          "type": "integer",
          "minimum": 15,
          "maximum": 60
        },
        "coordination_store": {
          "const": "git_common_dir"
        },
        "completion_write_branch": {
          "const": "default"
        },
        "dirty_worktree_policy": {
          "const": "fail_closed"
        }
      }
    },
    "claude_hooks": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "source",
        "project_plugin_link",
        "session_start",
        "post_tool_reconcile",
        "task_completed_gate"
      ],
      "properties": {
        "source": {
          "type": "string",
          "enum": [
            "plugin",
            "project",
            "disabled"
          ]
        },
        "project_plugin_link": {
          "$ref": "#/$defs/repoRelative"
        },
        "session_start": {
          "type": "boolean"
        },
        "post_tool_reconcile": {
          "type": "boolean"
        },
        "task_completed_gate": {
          "type": "boolean"
        }
      }
    },
    "path_policy": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "authority",
        "stored_paths",
        "allow_outside_repository",
        "follow_content_symlinks_outside_repository"
      ],
      "properties": {
        "authority": {
          "const": "caller-repository"
        },
        "stored_paths": {
          "const": "repository-relative"
        },
        "allow_outside_repository": {
          "const": false
        },
        "follow_content_symlinks_outside_repository": {
          "const": false
        }
      }
    }
  },
  "allOf": [
    {
      "if": {
        "properties": {
          "execution_tracker": {
            "properties": {
              "mode": {
                "enum": [
                  "github",
                  "both"
                ]
              }
            }
          }
        }
      },
      "then": {
        "properties": {
          "github": {
            "properties": {
              "enabled": {
                "const": true
              }
            }
          }
        }
      }
    }
  ],
  "$defs": {
    "repoRelative": {
      "type": "string",
      "minLength": 1,
      "pattern": "^(?!/)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"
    }
  }
}

{
  "schema_version": "1.0.0",
  "template_version": "1.0.0",
  "placeholder_tokens": ["<", "TBD", "TODO", "未定"],
  "not_applicable_format": "N/A: <reason>",
  "common_frontmatter": {
    "template": "common-frontmatter.md",
    "required": ["graph_node_id", "artifact_kind", "artifact_subtypes", "title", "project_id", "domain", "status", "priority", "start_date", "target_date", "iteration", "owners", "tags", "file_path", "template_id", "template_version", "confirmation_status", "evaluation_status", "confirmation_evidence", "source_lineage", "created_at", "updated_at", "depends_on", "related_nodes", "resource_scope", "purpose", "goal", "scope_in", "scope_out", "acceptance", "architecture_refs", "parent_feature", "feature_package_id", "phase_ref", "classification_confidence", "classification_reason", "classification_candidates", "tracker_binding", "beads_linkage", "github_publication", "issue_linkage", "github_project_linkages", "pull_request_linkages", "execution_contexts", "completion_evidence", "implementation_readiness"]
  },
  "artifacts": {
    "issue": {
      "template": "issue.md",
      "required_sections": ["概要", "背景と問題", "現在の挙動", "期待する挙動", "再現手順またはユースケース", "影響と優先度", "スコープ", "関連グラフ", "受入条件", "検証証跡"]
    },
    "task": {
      "template": "task.md",
      "required_sections": ["目的", "背景", "入力と前提条件", "出力と成果物", "依存関係", "実装対象", "Write scope と競合制約", "GitHub publication", "実行手順", "受入条件", "検証方法", "リスクとロールバック", "Handoff"],
      "conditional_templates": {"system_development": "system-task-spec.md"},
      "conditional_required_sections": {"system_development": ["Workstream applicability", "Architecture and deploy unit", "Verification and evidence", "Rollout and rollback", "Tracker publication and completion intent"]}
    },
    "document": {
      "template": "document.md",
      "required_sections": ["目的", "対象読者", "要約", "本文", "決定事項", "運用・更新方法", "関連資料", "変更履歴"]
    },
    "specification": {
      "template": "specification.md",
      "required_sections": ["目的と成功状態", "スコープ", "用語と主体", "ユースケースとユーザーフロー", "機能要件", "非機能要件", "UI・状態遷移", "ビジネスルールと検証", "API契約", "データモデル", "認証・認可", "エラー・例外・回復", "イベント・非同期処理", "可観測性", "互換性・移行・リリース", "テストと受入条件", "未決事項"],
      "conditional_templates": {"api_changed": "api-contract.md"}
    },
    "architecture": {
      "template": "architecture.md",
      "required_sections": ["Architecture overview", "Context and drivers", "Goals and non-goals", "System context and boundaries", "Container and component view", "Cross-cutting contracts", "Subtype architecture", "Architecture decisions", "Delivery, migration and rollback", "Risks and verification"],
      "subtype_templates": {
        "frontend": "architecture-frontend.md",
        "backend": "architecture-backend.md",
        "infrastructure": "architecture-infrastructure.md",
        "data": "architecture-data.md",
        "security": "architecture-security.md"
      },
      "subtype_policy": "one_or_more_or_explicit_not_applicable"
    },
    "feature": {
      "template": "feature.md",
      "required_sections": ["目的", "到達状態", "スコープ", "受入", "アーキテクチャ参照", "機能間依存", "Handoff"],
      "note": "マクロ層の機能単位ノード。purpose/goal/scope_in/scope_out/acceptance/architecture_refsを本文床として保持し、機能間依存は既存depends_onを流用する (MM-01, MM-11)。細タスク仕様書生成は external plugin system-dev-planner (ミクロ層) へ委譲し本テンプレートでは扱わない"
    }
  },
  "graph_projection": {
    "template": "task-graph-node.md",
    "required_fields": ["graph_node_id", "artifact_kind", "file_path", "goal", "depends_on", "touches", "acceptance", "verification", "handoff_route"],
    "root_map": {
      "issue": "issues/",
      "task": "tasks/",
      "specification": "specs/",
      "architecture": "architecture/",
      "feature": "features/",
      "document": "docs/"
    }
  },
  "system_plan": {
    "phase_template": null,
    "legacy_phase_template": "system-phase-spec.md (compatibility only; runtime emission forbidden)",
    "task_overlay": "system-task-spec.md",
    "task_overlay_status": "pointer_to_canonical",
    "task_overlay_canonical": "plugin-plans/system-dev-planner/references/system-task-spec-template.md",
    "runtime_emission_owner": "system-dev-planner (dev-graph はruntime task specをemitせず登録・投影・完了収束のみ担う。templates/system-task-spec.md は後方互換のpointerで、節構成・必須フィールドの正本は canonical 側)",
    "system_task_required_fields": ["parent_feature", "feature_package_id", "phase_ref"],
    "rule": "one feature execution package contains exactly 13 executable task artifacts, one for each P01..P13; no separate phase-document set and no variable-N canonical tasks",
    "feature_boundary": "system-dev-planner consumes exactly one dev-graph feature node (purpose/goal/scope_in/scope_out/acceptance/architecture_refs) as structured input context and never creates feature nodes; its promoted typed tasks register back into dev-graph with parent_feature=当該feature (MM-11)"
  },
  "readiness": {
    "states": ["complete", "incomplete", "not_applicable"],
    "complete_when": "all required fields and sections are substantive, all referenced nodes resolve, and conditional templates are satisfied",
    "fail_closed_on": ["missing_required_frontmatter", "missing_required_section", "placeholder_only_section", "unresolved_graph_reference", "conditional_template_missing", "path_parity_error"]
  }
}

